<h2>Categorias</h2><form method='post' action='<?= base_url('/categories') ?>' class='row g-2 mb-3'><?= csrf_field() ?><div class='col-md-4'><input name='name' class='form-control' placeholder='Nome da categoria' required></div><div class='col-md-2'><button class='btn btn-success'>Salvar</button></div></form><table class='table'><tr><th>Nome</th><th>Status</th><th>Ações</th></tr><?php foreach($items as $i): ?><tr><td><?= e($i['name']) ?></td><td><?= $i['status']?'Ativo':'Inativo' ?></td><td><form method='post' action='<?= base_url('/categories/toggle') ?>' class='d-inline'><?= csrf_field() ?><input type='hidden' name='id' value='<?= $i['id'] ?>'><button class='btn btn-sm btn-outline-primary'>Ativar/Desativar</button></form> <form method='post' action='<?= base_url('/categories/delete') ?>' class='d-inline'><?= csrf_field() ?><input type='hidden' name='id' value='<?= $i['id'] ?>'><button class='btn btn-sm btn-outline-danger'>Excluir</button></form></td></tr><?php endforeach; ?></table>
